import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface MonthlyRevenue {
  month: string;
  revenue: number;
}

interface RevenueData {
  totalRevenue: number;
  growthPercentage: number;
  monthlyRevenueTrend: MonthlyRevenue[];
}

export default function Widget() {
  const revenueData = response.data as RevenueData;
  const { totalRevenue, growthPercentage, monthlyRevenueTrend } = revenueData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#121212', color: '#fff' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Total Revenue
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FF5722' }}>
              ${totalRevenue.toLocaleString()}
            </Typography>
            <Typography variant="caption" sx={{ color: growthPercentage >= 0 ? '#4CAF50' : '#F44336' }}>
              {growthPercentage >= 0 ? '+' : ''}{growthPercentage.toFixed(2)}% vs last month
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: monthlyRevenueTrend.map(m => m.revenue),
                  color: '#0D47A1',
                  label: 'Monthly Revenue',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: monthlyRevenueTrend.map(m => m.month),
                  id: 'months',
                },
              ]}
              yAxis={[{ id: 'revenue' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="months"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsYAxis
                axisId="revenue"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
